mapper.select:
SELECT n.*, a.name AS actor_name, a.status AS actor_status FROM notification n LEFT JOIN users a ON n.actor_id = a.id WHERE n.user_id = #{userId}
AND COALESCE(n.destination_platform, 'ALL') IN ('ALL', #{platform})
ORDER BY n.created_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.delete:
